  const badgeGroups = [];
  let remainingTrails = totalTrails;

  // --- Render 500s badges ---
  const num500 = Math.floor(remainingTrails / 500);
  if (num500 > 0) {
    const currentGroup = [];
    for (let i = 0; i < num500; i++) {
      currentGroup.push(
        <div key={`500-${i}`} className="relative first:ml-0 -ml-14">
