import React, { useState, useEffect } from 'react';
import Modal from './Modal';
import Button from './Button';
import Input from './Input';

interface CustomAmountModalProps {
  isOpen: boolean;
  onClose: () => void;
  onSubmit: (amount: number, description: string) => void;
  transactionType: 'Aufladung' | 'Abbuchung';
}

const CustomAmountModal: React.FC<CustomAmountModalProps> = ({ isOpen, onClose, onSubmit, transactionType }) => {
  const [amount, setAmount] = useState('');
  const [description, setDescription] = useState('');
  const [errors, setErrors] = useState<{ amount?: string; description?: string }>({});

  useEffect(() => {
    if (isOpen) {
      setAmount('');
      setDescription('');
      setErrors({});
    }
  }, [isOpen]);

  const validate = () => {
    const newErrors: { amount?: string; description?: string } = {};
    const numericAmount = parseFloat(amount.replace(',', '.'));

    if (!amount) {
      newErrors.amount = 'Betrag ist erforderlich.';
    } else if (isNaN(numericAmount) || numericAmount <= 0) {
      newErrors.amount = 'Bitte geben Sie einen gültigen, positiven Betrag ein.';
    }

    if (transactionType === 'Abbuchung' && !description.trim()) {
      newErrors.description = 'Beschreibung ist für Abbuchungen erforderlich.';
    }

    setErrors(newErrors);
    return Object.keys(newErrors).length === 0;
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (validate()) {
      onSubmit(parseFloat(amount.replace(',', '.')), description);
    }
  };

  const title = transactionType === 'Aufladung' ? 'Individuelle Aufladung' : 'Individuelle Abbuchung';

  return (
    <Modal isOpen={isOpen} onClose={onClose} title={title} className="max-w-md">
      <form onSubmit={handleSubmit} className="p-0">
        <div className="space-y-4">
          <Input
            id="customAmount"
            label="Betrag in €"
            type="number"
            value={amount}
            onChange={(e) => setAmount(e.target.value)}
            placeholder="z.B. 50.00"
            error={errors.amount}
            step="0.01"
            min="0.01"
            autoFocus
          />
          <Input
            id="customDescription"
            label={`Beschreibung ${transactionType === 'Abbuchung' ? '' : '(optional)'}`}
            type="text"
            value={description}
            onChange={(e) => setDescription(e.target.value)}
            placeholder="z.B. Vorauszahlung, Korrektur..."
            error={errors.description}
          />
        </div>
        <div className="p-4 border-t border-gray-200 mt-6 flex justify-end space-x-3">
          <Button variant="outline" type="button" onClick={onClose}>
            Abbrechen
          </Button>
          <Button variant="success" type="submit">
            Weiter zur Bestätigung
          </Button>
        </div>
      </form>
    </Modal>
  );
};

export default CustomAmountModal;

import React from 'react';
import Modal from './Modal';
import Button from './Button';
import { ArrowUpCircleIcon, ArrowDownCircleIcon, ClipboardIcon, EditIcon } from './Icons';

interface TransactionTypeSelectionModalProps {
  isOpen: boolean;
  onClose: () => void;
  onSelectType: (type: 'Aufladung' | 'Trails' | 'Workshop' | 'customRecharge' | 'customDebit') => void;
  customerBalance: number;
}

const TransactionTypeSelectionModal: React.FC<TransactionTypeSelectionModalProps> = ({
  isOpen,
  onClose,
  onSelectType,
  customerBalance,
}) => {
  const TRAIL_COST = 18;
  const WORKSHOP_COST = 36;
  const RECHARGE_AMOUNT = 216;
  const isTrailDisabled = customerBalance < TRAIL_COST;
  const isWorkshopDisabled = customerBalance < WORKSHOP_COST;

  const handleSelect = (type: 'Aufladung' | 'Trails' | 'Workshop' | 'customRecharge' | 'customDebit') => {
    onSelectType(type);
    onClose();
  };

  return (
    <Modal isOpen={isOpen} onClose={onClose} title="Transaktion auswählen" className="max-w-sm">
      <div className="p-4 space-y-4 text-center">
        <p className="text-gray-700">Wählen Sie eine Standard-Transaktion oder geben Sie einen individuellen Betrag ein.</p>

        {/* Standard Transactions */}
        <div className="flex flex-col space-y-3">
          <Button
            variant="success"
            icon={ArrowUpCircleIcon}
            onClick={() => handleSelect('Aufladung')}
          >
            Aufladung ({RECHARGE_AMOUNT.toLocaleString('de-DE', { style: 'currency', currency: 'EUR' })})
          </Button>
          <Button
            variant="danger"
            icon={ArrowDownCircleIcon}
            onClick={() => handleSelect('Trails')}
            disabled={isTrailDisabled}
            title={isTrailDisabled ? `Nicht genügend Guthaben. Benötigt: ${TRAIL_COST.toLocaleString('de-DE', { style: 'currency', currency: 'EUR' })}` : ''}
          >
            Trails ({TRAIL_COST.toLocaleString('de-DE', { style: 'currency', currency: 'EUR' })})
          </Button>
          <Button
            variant="info"
            icon={ClipboardIcon}
            onClick={() => handleSelect('Workshop')}
            disabled={isWorkshopDisabled}
            title={isWorkshopDisabled ? `Nicht genügend Guthaben. Benötigt: ${WORKSHOP_COST.toLocaleString('de-DE', { style: 'currency', currency: 'EUR' })}` : ''}
          >
            Seminar/Event ({WORKSHOP_COST.toLocaleString('de-DE', { style: 'currency', currency: 'EUR' })})
          </Button>
        </div>

        {(isTrailDisabled || isWorkshopDisabled) && (
            <p className="text-sm text-red-600 mt-2">
                Einige Standard-Abbuchungen sind wegen zu geringem Guthaben nicht verfügbar.
            </p>
        )}

        {/* Separator */}
        <div className="relative py-2">
          <div className="absolute inset-0 flex items-center" aria-hidden="true">
            <div className="w-full border-t border-gray-300" />
          </div>
          <div className="relative flex justify-center">
            <span className="bg-white px-2 text-sm text-gray-500">Oder</span>
          </div>
        </div>

        {/* Custom Amount Transactions */}
        <div className="flex flex-col space-y-3">
            <Button
              variant="outline"
              icon={EditIcon}
              onClick={() => handleSelect('customRecharge')}
            >
              Individuelle Aufladung
            </Button>
            <Button
              variant="outline"
              icon={EditIcon}
              onClick={() => handleSelect('customDebit')}
            >
              Individuelle Abbuchung
            </Button>
        </div>

      </div>
      <div className="p-4 border-t border-gray-200 flex justify-end">
        <Button variant="outline" onClick={onClose}>
          Abbrechen
        </Button>
      </div>
    </Modal>
  );
};

export default TransactionTypeSelectionModal;

