      setSeminars(currentSeminars.toString());
      setTrailsError('');
      setSeminarsError('');
    }
  }, [isOpen, currentTrails, currentSeminars]);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    const numTrails = parseInt(trails, 10);
