      <Button onClick={onDismiss} variant="ghost" size="sm" className="text-gray-300 hover:bg-gray-700">Später</Button>
      <Button onClick={onInstall} variant="primary" size="sm" icon={PlusIcon}>Installieren</Button>
    </div>
  </div>
);


